export enum StripType {
  PHYSICAL = 'PHYSICAL',
  VIRTUAL = 'VIRTUAL'
}

export interface ChannelSettings {
  id: number;
  name: string;
  type: StripType;
  gain: number; // 0 to 2
  mute: boolean;
  solo: boolean;
  pan: number; // -1 to 1
  eq: {
    low: number;
    mid: number;
    high: number;
  };
  gate: {
    threshold: number;
    active: boolean;
  };
  compressor: {
    threshold: number;
    ratio: number;
    active: boolean;
  };
  routing: boolean[]; // 8 output busses
}

export interface MasterSettings {
  reverb: number;
  delay: number;
  masterGain: number;
}

export interface AudioMeterData {
  rms: number;
  peak: number;
}

import React from 'react';
