import { ChannelSettings, MasterSettings, StripType } from '../types';

class AudioEngine {
  private context: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private inputNodes: (GainNode | null)[] = Array(8).fill(null);
  private analyzers: (AnalyserNode | null)[] = Array(8).fill(null);
  private initialized = false;

  async initialize() {
    if (this.initialized) return;

    this.context = new (window.AudioContext || (window as any).webkitAudioContext)({
      latencyHint: 'interactive',
      sampleRate: 48000
    });

    this.masterGain = this.context.createGain();
    this.masterGain.connect(this.context.destination);

    for (let i = 0; i < 8; i++) {
      const gain = this.context.createGain();
      const analyzer = this.context.createAnalyser();
      analyzer.fftSize = 256;
      gain.connect(analyzer);
      gain.connect(this.masterGain);
      this.inputNodes[i] = gain;
      this.analyzers[i] = analyzer;
    }

    this.initialized = true;
    console.log("Audio Engine Initialized at 48kHz");
  }

  async startMic() {
    if (!this.context) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = this.context.createMediaStreamSource(stream);
      // Connect first physical strip to real mic
      source.connect(this.inputNodes[0]!);
    } catch (err) {
      console.error("Mic access denied", err);
    }
  }

  updateChannel(id: number, settings: ChannelSettings) {
    if (!this.inputNodes[id]) return;
    const gainNode = this.inputNodes[id]!;
    const targetGain = settings.mute ? 0 : settings.gain;
    gainNode.gain.setTargetAtTime(targetGain, this.context!.currentTime, 0.05);
  }

  getMeter(id: number): number {
    if (!this.analyzers[id]) return 0;
    const data = new Uint8Array(this.analyzers[id]!.frequencyBinCount);
    this.analyzers[id]!.getByteFrequencyData(data);
    const sum = data.reduce((a, b) => a + b, 0);
    return sum / data.length / 255;
  }

  resume() {
    this.context?.resume();
  }
}

export const audioEngine = new AudioEngine();

import { GoogleGenAI } from "@google/genai";

export const getGeminiOptimization = async (channelName: string, type: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Act as a senior audio engineer. Provide optimization suggestions for a ${type} channel named "${channelName}". Suggest EQ points, compression ratio, and noise gate threshold for professional performance. Respond in brief bullet points.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (err) {
    console.error("Gemini failed", err);
    return "Could not fetch AI suggestions at this time.";
  }
};

