import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ChannelSettings, StripType } from './types';
import { PHYSICAL_INPUTS, VIRTUAL_INPUTS, TOTAL_INPUTS } from './constants';
import MixerStrip from './components/MixerStrip';
import MasterSection from './components/MasterSection';
import VbanPanel from './components/VbanPanel';
import { audioEngine } from './services/audioEngine';
import { getGeminiOptimization } from './services/geminiService';
import { Loader2, AlertTriangle, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelSettings[]>([]);
  const [masterGain, setMasterGain] = useState(1);
  const [isInitialized, setIsInitialized] = useState(false);
  const [meters, setMeters] = useState<number[]>(new Array(TOTAL_INPUTS).fill(0));
  const [aiLoading, setAiLoading] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);

  // Initialize channels on mount (Load from localStorage if available)
  useEffect(() => {
    const loadSettings = () => {
      try {
        const saved = localStorage.getItem('omnimix_settings');
        if (saved) {
          const parsed = JSON.parse(saved);
          if (parsed.channels && Array.isArray(parsed.channels) && parsed.channels.length === TOTAL_INPUTS) {
            setChannels(parsed.channels);
            setMasterGain(parsed.masterGain ?? 1);
            return;
          }
        }
      } catch (e) {
        console.error("Failed to load settings from localStorage", e);
      }

      // Default initialization if no save found
      const initialChannels: ChannelSettings[] = [];
      for (let i = 0; i < TOTAL_INPUTS; i++) {
        const isPhysical = i < PHYSICAL_INPUTS;
        initialChannels.push({
          id: i,
          name: isPhysical ? `In ${i + 1}` : `VAIO ${i - PHYSICAL_INPUTS + 1}`,
          type: isPhysical ? StripType.PHYSICAL : StripType.VIRTUAL,
          gain: 1,
          mute: false,
          solo: false,
          pan: 0,
          eq: { low: 0, mid: 0, high: 0 },
          gate: { threshold: -60, active: false },
          compressor: { threshold: -20, ratio: 4, active: false },
          routing: [true, false, false, false, false, false, false, false]
        });
      }
      setChannels(initialChannels);
    };

    loadSettings();
  }, []);

  // Save settings to localStorage whenever they change
  useEffect(() => {
    if (channels.length > 0) {
      localStorage.setItem('omnimix_settings', JSON.stringify({ channels, masterGain }));
    }
  }, [channels, masterGain]);

  const handleInitialize = async () => {
    await audioEngine.initialize();
    await audioEngine.startMic();

    // Sync current state to the audio engine now that it's active
    channels.forEach(ch => audioEngine.updateChannel(ch.id, ch));

    setIsInitialized(true);
  };

  const updateChannel = (id: number, settings: Partial<ChannelSettings>) => {
    setChannels(prev => {
      const updated = [...prev];
      updated[id] = { ...updated[id], ...settings };
      // Real-time update if engine is running
      if (isInitialized) {
        audioEngine.updateChannel(id, updated[id]);
      }
      return updated;
    });
  };

  // Meter polling loop
  useEffect(() => {
    if (!isInitialized) return;
    const interval = setInterval(() => {
      setMeters(channels.map((_, i) => audioEngine.getMeter(i)));
    }, 50);
    return () => clearInterval(interval);
  }, [isInitialized, channels]);

  const runAiOptimization = async () => {
    setAiLoading(true);
    const advice = await getGeminiOptimization("Vocal Mic", "Physical XLR");
    setAiAdvice(advice || "No advice available.");
    setAiLoading(false);
  };

  if (!isInitialized) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#0a0a0a] text-white p-6">
        <div className="max-w-md w-full bg-[#1a1a1a] p-8 rounded-lg border border-[#333] shadow-2xl flex flex-col items-center space-y-6 text-center">
          <div className="w-20 h-20 bg-blue-600 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(37,99,235,0.4)]">
            <ShieldCheck size={48} className="text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-black italic tracking-tight mb-2 uppercase">OMNIMIX ENGINE</h1>
            <p className="text-gray-400 text-sm leading-relaxed">
              To simulate the requested 5.1/7.1 matrix and low-latency WDM drivers, we must initialize the Web Audio context. 
              <br/><br/>
              <span className="text-yellow-500/80 font-bold flex items-center justify-center gap-1">
                <AlertTriangle size={14} /> KERNEL MODE SIMULATION ACTIVE
              </span>
            </p>
          </div>
          <button 
            onClick={handleInitialize}
            className="w-full py-4 bg-white text-black font-black uppercase tracking-widest rounded hover:bg-gray-200 transition-all transform active:scale-95"
          >
            Engage Audio Engine
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-[#121212] select-none">
      {/* Top Header Bar */}
      <div className="bg-[#1a1a1a] border-b border-[#333] p-2 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className="px-3 py-1 bg-black border border-[#333] rounded text-[10px] font-bold text-white italic">
            OMNIMIX V2.4 PROFESSIONAL
          </div>
          <div className="flex gap-4 text-[10px] font-bold opacity-60">
            <span>FILE</span>
            <span>EDIT</span>
            <span>DRIVERS</span>
            <span>SYSTEM</span>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <div className="flex flex-col items-end">
             <span className="text-[10px] opacity-40">DRIVER: WASAPI EXCLUSIVE</span>
             <span className="text-[10px] text-green-500 font-mono">LATENCY: 1.2ms (STABLE)</span>
           </div>
        </div>
      </div>

      {/* Main Console Area */}
      <div className="flex-grow flex overflow-x-auto overflow-y-hidden">
        {channels.map((channel, i) => (
          <MixerStrip 
            key={channel.id} 
            settings={channel} 
            onChange={updateChannel}
            meterValue={meters[i]}
          />
        ))}
        <MasterSection 
          masterGain={masterGain} 
          onGainChange={setMasterGain}
          onOptimize={runAiOptimization}
        />
      </div>

      {/* AI Advice Overlay */}
      {aiAdvice && (
        <div className="fixed bottom-24 right-8 w-80 bg-blue-900/90 border border-blue-400 p-4 rounded-lg shadow-2xl z-50 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex justify-between items-start mb-2">
            <h4 className="text-xs font-bold text-blue-200 flex items-center gap-2">
              <Loader2 className={aiLoading ? 'animate-spin' : ''} size={12} />
              GEMINI AI CO-PILOT
            </h4>
            <button onClick={() => setAiAdvice(null)} className="text-blue-200 hover:text-white">×</button>
          </div>
          <div className="text-[11px] text-blue-50 leading-relaxed whitespace-pre-wrap">
            {aiLoading ? "Analyzing audio stream..." : aiAdvice}
          </div>
        </div>
      )}

      {/* Status Footer */}
      <VbanPanel />
    </div>
  );
};

