import { ChannelSettings, MasterSettings, StripType } from '../types';

class AudioEngine {
  private context: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private inputNodes: (GainNode | null)[] = Array(8).fill(null);
  private analyzers: (AnalyserNode | null)[] = Array(8).fill(null);
  private initialized = false;

  async initialize() {
    if (this.initialized) return;

    this.context = new (window.AudioContext || (window as any).webkitAudioContext)({
      latencyHint: 'interactive',
      sampleRate: 48000
    });

    this.masterGain = this.context.createGain();
    this.masterGain.connect(this.context.destination);

    for (let i = 0; i < 8; i++) {
      const gain = this.context.createGain();
      const analyzer = this.context.createAnalyser();
      analyzer.fftSize = 256;
      gain.connect(analyzer);
      gain.connect(this.masterGain);
      this.inputNodes[i] = gain;
      this.analyzers[i] = analyzer;
    }

    this.initialized = true;
    console.log("Audio Engine Initialized at 48kHz");
  }

  async startMic() {
    if (!this.context) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = this.context.createMediaStreamSource(stream);
      // Connect first physical strip to real mic
      source.connect(this.inputNodes[0]!);
    } catch (err) {
      console.error("Mic access denied", err);
    }
  }

  updateChannel(id: number, settings: ChannelSettings) {
    if (!this.inputNodes[id]) return;
    const gainNode = this.inputNodes[id]!;
    const targetGain = settings.mute ? 0 : settings.gain;
    gainNode.gain.setTargetAtTime(targetGain, this.context!.currentTime, 0.05);
  }

  setMasterVolume(volume: number) {
    if (this.masterGain && this.context) {
      this.masterGain.gain.setTargetAtTime(volume, this.context.currentTime, 0.05);
    }
  }

  getMeter(id: number): number {
    if (!this.analyzers[id]) return 0;
    const data = new Uint8Array(this.analyzers[id]!.frequencyBinCount);
    this.analyzers[id]!.getByteFrequencyData(data);
    const sum = data.reduce((a, b) => a + b, 0);
    return sum / data.length / 255;
  }

  resume() {
    this.context?.resume();
  }
}

export const audioEngine = new AudioEngine();

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ChannelSettings, StripType } from './types';
import { PHYSICAL_INPUTS, VIRTUAL_INPUTS, TOTAL_INPUTS } from './constants';
import MixerStrip from './components/MixerStrip';
import MasterSection from './components/MasterSection';
import VbanPanel from './components/VbanPanel';
import { audioEngine } from './services/audioEngine';
import { getGeminiOptimization } from './services/geminiService';
import { Loader2, AlertTriangle, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelSettings[]>([]);
  const [masterGain, setMasterGain] = useState(1);
  const [isInitialized, setIsInitialized] = useState(false);
  const [meters, setMeters] = useState<number[]>(new Array(TOTAL_INPUTS).fill(0));
  const [aiLoading, setAiLoading] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);

  // Initialize channels on mount (Load from localStorage if available)
  useEffect(() => {
    const loadSettings = () => {
      try {
        const saved = localStorage.getItem('omnimix_settings');
        if (saved) {
          const parsed = JSON.parse(saved);
          if (parsed.channels && Array.isArray(parsed.channels) && parsed.channels.length === TOTAL_INPUTS) {
            setChannels(parsed.channels);
            // Load master gain, default to 1 if not present
            setMasterGain(parsed.masterGain !== undefined ? parsed.masterGain : 1);
            return;
          }
        }
      } catch (e) {
        console.error("Failed to load settings from localStorage", e);
      }

      // Default initialization if no save found
      const initialChannels: ChannelSettings[] = [];
      for (let i = 0; i < TOTAL_INPUTS; i++) {
        const isPhysical = i < PHYSICAL_INPUTS;
        initialChannels.push({
          id: i,
          name: isPhysical ? `In ${i + 1}` : `VAIO ${i - PHYSICAL_INPUTS + 1}`,
          type: isPhysical ? StripType.PHYSICAL : StripType.VIRTUAL,
          gain: 1,
          mute: false,
          solo: false,
          pan: 0,
          eq: { low: 0, mid: 0, high: 0 },
          gate: { threshold: -60, active: false },
          compressor: { threshold: -20, ratio: 4, active: false },
          routing: [true, false, false, false, false, false, false, false]
        });
      }
      setChannels(initialChannels);
    };

    loadSettings();
  }, []);

  // Save settings to localStorage whenever they change
  useEffect(() => {
    if (channels.length > 0) {
      localStorage.setItem('omnimix_settings', JSON.stringify({ channels, masterGain }));
    }
  }, [channels, masterGain]);

  // Sync master gain to audio engine
  useEffect(() => {
    if (isInitialized) {
      audioEngine.setMasterVolume(masterGain);
    }
  }, [masterGain, isInitialized]);

  const handleInitialize = async () => {
    await audioEngine.initialize();
    await audioEngine.startMic();

    // Sync current state to the audio engine now that it's active
    // We must respect the solo state immediately upon initialization
    const anySolo = channels.some(ch => ch.solo);
    channels.forEach(ch => {
        const effectiveMute = anySolo ? !ch.solo : ch.mute;
        audioEngine.updateChannel(ch.id, { ...ch, mute: effectiveMute });
    });

    // Apply initial master gain
    audioEngine.setMasterVolume(masterGain);

    setIsInitialized(true);
  };

  const updateChannel = (id: number, settings: Partial<ChannelSettings>) => {
    setChannels(prev => {
      const updated = [...prev];
      updated[id] = { ...updated[id], ...settings };
      // Real-time update if engine is running
      if (isInitialized) {
        const anySolo = updated.some(ch => ch.solo);
        // We must update all channels because toggling solo on one affects the others
        updated.forEach(ch => {
            const effectiveMute = anySolo ? !ch.solo : ch.mute;
            // Send effective mute state to engine without modifying the actual channel data "mute" property
            audioEngine.updateChannel(ch.id, { ...ch, mute: effectiveMute });
        });
      }
      return updated;
    });
  };

  // Meter polling loop
  useEffect(() => {
    if (!isInitialized) return;
    const interval = setInterval(() => {
      setMeters(channels.map((_, i) => audioEngine.getMeter(i)));
    }, 50);
    return () => clearInterval(interval);
  }, [isInitialized, channels]);

  const runAiOptimization = async () => {
    setAiLoading(true);
    const advice = await getGeminiOptimization("Vocal Mic", "Physical XLR");
    setAiAdvice(advice || "No advice available.");
    setAiLoading(false);
  };

  if (!isInitialized) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#0a0a0a] text-white p-6">
        <div className="max-w-md w-full bg-[#1a1a1a] p-8 rounded-lg border border-[#333] shadow-2xl flex flex-col items-center space-y-6 text-center">
          <div className="w-20 h-20 bg-blue-600 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(37,99,235,0.4)]">
            <ShieldCheck size={48} className="text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-black italic tracking-tight mb-2 uppercase">OMNIMIX ENGINE</h1>
            <p className="text-gray-400 text-sm leading-relaxed">
              To simulate the requested 5.1/7.1 matrix and low-latency WDM drivers, we must initialize the Web Audio context. 
              <br/><br/>
              <span className="text-yellow-500/80 font-bold flex items-center justify-center gap-1">
                <AlertTriangle size={14} /> KERNEL MODE SIMULATION ACTIVE
              </span>
            </p>
          </div>
          <button 
            onClick={handleInitialize}
            className="w-full py-4 bg-white text-black font-black uppercase tracking-widest rounded hover:bg-gray-200 transition-all transform active:scale-95"
          >
            Engage Audio Engine
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-[#121212] select-none">
      {/* Top Header Bar */}
      <div className="bg-[#1a1a1a] border-b border-[#333] p-2 flex justify-between items-center">
        <div className="flex items-center gap-4">
          <div className="px-3 py-1 bg-black border border-[#333] rounded text-[10px] font-bold text-white italic">
            OMNIMIX V2.4 PROFESSIONAL
          </div>
          <div className="flex gap-4 text-[10px] font-bold opacity-60">
            <span>FILE</span>
            <span>EDIT</span>
            <span>DRIVERS</span>
            <span>SYSTEM</span>
          </div>
        </div>
        <div className="flex items-center gap-4">
           <div className="flex flex-col items-end">
             <span className="text-[10px] opacity-40">DRIVER: WASAPI EXCLUSIVE</span>
             <span className="text-[10px] text-green-500 font-mono">LATENCY: 1.2ms (STABLE)</span>
           </div>
        </div>
      </div>

      {/* Main Console Area */}
      <div className="flex-grow flex overflow-x-auto overflow-y-hidden">
        {channels.map((channel, i) => (
          <MixerStrip 
            key={channel.id} 
            settings={channel} 
            onChange={updateChannel}
            meterValue={meters[i]}
          />
        ))}
        <MasterSection 
          masterGain={masterGain} 
          onGainChange={setMasterGain}
          onOptimize={runAiOptimization}
        />
      </div>

      {/* AI Advice Overlay */}
      {aiAdvice && (
        <div className="fixed bottom-24 right-8 w-80 bg-blue-900/90 border border-blue-400 p-4 rounded-lg shadow-2xl z-50 animate-in fade-in slide-in-from-bottom-4">
          <div className="flex justify-between items-start mb-2">
            <h4 className="text-xs font-bold text-blue-200 flex items-center gap-2">
              <Loader2 className={aiLoading ? 'animate-spin' : ''} size={12} />
              GEMINI AI CO-PILOT
            </h4>
            <button onClick={() => setAiAdvice(null)} className="text-blue-200 hover:text-white">×</button>
          </div>
          <div className="text-[11px] text-blue-50 leading-relaxed whitespace-pre-wrap">
            {aiLoading ? "Analyzing audio stream..." : aiAdvice}
          </div>
        </div>
      )}

      {/* Status Footer */}
      <VbanPanel />
    </div>
  );
};

export default App;

export enum StripType {
  PHYSICAL = 'PHYSICAL',
  VIRTUAL = 'VIRTUAL'
}

export interface ChannelSettings {
  id: number;
  name: string;
  type: StripType;
  deviceId?: string; // Hardware Device ID
  gain: number; // 0 to 2 (where 1 is 0dB)
  mute: boolean;
  solo: boolean;
  monitor: boolean; // Input Monitoring (Playback Response)
  pan: number; // -1 to 1
  eq: {
    low: number; // dB
    mid: number; // dB
    high: number; // dB
  };
  gate: {
    threshold: number;
    active: boolean;
  };
  compressor: {
    threshold: number;
    ratio: number;
    active: boolean;
  };
  routing: boolean[]; // 8 output busses
}

export interface MasterSettings {
  reverb: number;
  delay: number;
  masterGain: number;
}

export interface AudioMeterData {
  rms: number;
  peak: number;
}

import { ChannelSettings, MasterSettings, StripType } from '../types';

interface ChannelStripNodes {
  source: MediaStreamAudioSourceNode | null;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  gain: GainNode;
  meterNode: AnalyserNode;
  monitorGain: GainNode; // Used for monitoring toggle
}

class AudioEngine {
  private context: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private masterLimiter: DynamicsCompressorNode | null = null;
  private channels: ChannelStripNodes[] = [];
  private initialized = false;

  async initialize() {
    if (this.initialized) return;

    // Low latency context
    this.context = new (window.AudioContext || (window as any).webkitAudioContext)({
      latencyHint: 'interactive',
      sampleRate: 48000
    });

    // Master Bus Chain: MasterGain -> Limiter -> Destination
    this.masterGain = this.context.createGain();
    this.masterGain.gain.value = 1.0;

    // Brickwall Limiter to prevent clipping
    this.masterLimiter = this.context.createDynamicsCompressor();
    this.masterLimiter.threshold.value = -1.0;
    this.masterLimiter.knee.value = 0;
    this.masterLimiter.ratio.value = 20.0;
    this.masterLimiter.attack.value = 0.005;
    this.masterLimiter.release.value = 0.1;

    this.masterGain.connect(this.masterLimiter);
    this.masterLimiter.connect(this.context.destination);

    // Initialize Channel Strips
    for (let i = 0; i < 8; i++) {
      this.channels[i] = this.createChannelStrip();
    }

    this.initialized = true;
    console.log("Audio Engine Initialized: 48kHz, Low Latency, Limited Master");
  }

  private createChannelStrip(): ChannelStripNodes {
    if (!this.context) throw new Error("Context not initialized");

    const eqLow = this.context.createBiquadFilter();
    eqLow.type = 'lowshelf';
    eqLow.frequency.value = 80;

    const eqMid = this.context.createBiquadFilter();
    eqMid.type = 'peaking';
    eqMid.frequency.value = 2500;
    eqMid.Q.value = 1.0;

    const eqHigh = this.context.createBiquadFilter();
    eqHigh.type = 'highshelf';
    eqHigh.frequency.value = 12000;

    const gain = this.context.createGain();
    const monitorGain = this.context.createGain();
    const meterNode = this.context.createAnalyser();
    meterNode.fftSize = 256;
    meterNode.smoothingTimeConstant = 0.5;

    // Chain: Source -> Low -> Mid -> High -> Gain -> MonitorGain -> Master
    // Meter taps off before MonitorGain so you see levels even if muted/unmonitored (Pre-fader metering? usually post-fader but pre-mute. Let's do Post-Gain)

    eqLow.connect(eqMid);
    eqMid.connect(eqHigh);
    eqHigh.connect(gain);
    gain.connect(meterNode);
    gain.connect(monitorGain);
    monitorGain.connect(this.masterGain!);

    return {
      source: null,
      eqLow,
      eqMid,
      eqHigh,
      gain,
      meterNode,
      monitorGain
    };
  }

  async setInputDevice(id: number, deviceId: string) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: { 
          deviceId: { exact: deviceId },
          echoCancellation: false,
          autoGainControl: false,
          noiseSuppression: false,
          latency: 0
        } 
      });
      strip.source = this.context.createMediaStreamSource(stream);
      strip.source.connect(strip.eqLow);
    } catch (err) {
      console.error(`Failed to connect device ${deviceId} to channel ${id}`, err);
    }
  }

  async setDisplayMedia(id: number) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      // @ts-ignore
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true });
      // We only care about audio. Note: User must check "Share Audio" in the browser dialog.
      if (stream.getAudioTracks().length > 0) {
        strip.source = this.context.createMediaStreamSource(stream);
        strip.source.connect(strip.eqLow);
      } else {
        alert("No audio track found. Please ensure 'Share Audio' is checked.");
      }
    } catch (err) {
      console.error("Display media selection cancelled or failed", err);
    }
  }

  // Fallback for default mic
  async startMic() {
    if (!this.context) return;
    // Default to first channel
    try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const audioInput = devices.find(d => d.kind === 'audioinput');
        if (audioInput) {
            await this.setInputDevice(0, audioInput.deviceId);
        }
    } catch(e) {
        console.error("Default mic error", e);
    }
  }

  updateChannel(id: number, settings: ChannelSettings) {
    if (!this.channels[id] || !this.context) return;
    const strip = this.channels[id];
    const now = this.context.currentTime;

    // Gain & Mute
    // Note: Mute overrides monitor in this logic, effectively silencing the channel strip
    const targetGain = settings.mute ? 0 : settings.gain;
    strip.gain.gain.setTargetAtTime(targetGain, now, 0.02);

    // Monitor Toggle (Routing to Master)
    // If Monitor is ON, we let sound through monitorGain to Master.
    // If Monitor is OFF, we mute monitorGain (effectively removing it from Main Mix), but Meter still works.
    // Solo logic is handled in App.tsx by muting non-soloed channels.
    const monitorVal = settings.monitor ? 1 : 0;
    strip.monitorGain.gain.setTargetAtTime(monitorVal, now, 0.02);

    // EQ
    strip.eqLow.gain.setTargetAtTime(settings.eq.low, now, 0.1);
    strip.eqMid.gain.setTargetAtTime(settings.eq.mid, now, 0.1);
    strip.eqHigh.gain.setTargetAtTime(settings.eq.high, now, 0.1);
  }

  setMasterVolume(volume: number) {
    if (this.masterGain && this.context) {
      this.masterGain.gain.setTargetAtTime(volume, this.context.currentTime, 0.05);
    }
  }

  getMeter(id: number): number {
    if (!this.channels[id]) return 0;
    const analyzer = this.channels[id].meterNode;
    const data = new Uint8Array(analyzer.frequencyBinCount);
    analyzer.getByteFrequencyData(data);

    // Simple RMS-ish approximation
    let sum = 0;
    for(let i=0; i<data.length; i++) {
        sum += data[i];
    }
    const avg = sum / data.length;
    return avg / 128; // Normalize 0-1ish
  }

  resume() {
    this.context?.resume();
  }
}

export const audioEngine = new AudioEngine();

import React, { useEffect, useState, useRef } from 'react';
import { ChannelSettings, StripType } from '../types';
import { ICONS, CHANNEL_COLORS } from '../constants';
import { ChevronDown, Monitor, Mic } from 'lucide-react';

interface Props {
  settings: ChannelSettings;
  onChange: (id: number, settings: Partial<ChannelSettings>) => void;
  meterValue: number;
  availableDevices: MediaDeviceInfo[];
  onSelectDevice: (id: number, deviceId: string) => void;
  onSelectVirtual: (id: number) => void;
}

const Knob = ({ value, onChange, label, color }: { value: number, onChange: (v: number) => void, label: string, color?: string }) => {
    const [isDragging, setIsDragging] = useState(false);
    const startY = useRef(0);
    const startVal = useRef(0);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging) return;
            const deltaY = startY.current - e.clientY;
            // Sensitivity: 1px = 0.5dB
            let newVal = startVal.current + deltaY * 0.5;
            newVal = Math.max(-15, Math.min(15, newVal));
            onChange(newVal);
        };
        const handleMouseUp = () => setIsDragging(false);

        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, onChange]);

    // Map -15..15 to rotation -135..135
    const rotation = (value / 15) * 135;

    return (
        <div className="flex flex-col items-center">
            <span className="text-[9px] mb-1 opacity-50 select-none">{label}</span>
            <div 
                className="w-8 h-8 rounded-full skeuo-knob border border-[#333] cursor-ns-resize relative active:scale-95 transition-transform"
                onMouseDown={(e) => {
                    setIsDragging(true);
                    startY.current = e.clientY;
                    startVal.current = value;
                }}
            >
               <div 
                className="absolute top-1/2 left-1/2 w-0.5 h-3.5 bg-blue-400 rounded-full origin-bottom"
                style={{ 
                    transform: `translate(-50%, -100%) rotate(${rotation}deg)`,
                    backgroundColor: value === 0 ? '#60a5fa' : value > 0 ? '#ef4444' : '#60a5fa'
                }} 
               />
            </div>
            <span className="text-[8px] mt-1 opacity-40 font-mono">{value > 0 ? '+' : ''}{Math.round(value)}dB</span>
        </div>
    );
};

const MixerStrip: React.FC<Props> = ({ settings, onChange, meterValue, availableDevices, onSelectDevice, onSelectVirtual }) => {
  const isPhysical = settings.type === StripType.PHYSICAL;
  const color = CHANNEL_COLORS[settings.id];

  const handleGainChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange(settings.id, { gain: parseFloat(e.target.value) });
  };

  return (
    <div className="flex flex-col w-32 bg-[#1a1a1a] border-r border-[#333] h-full skeuo-shadow relative overflow-hidden group shrink-0">
      {/* Header / Input Select */}
      <div className="p-2 border-b border-[#333] bg-[#222]">
        <div className="flex items-center justify-between mb-1">
          <span className="text-[10px] font-bold opacity-60 uppercase tracking-tighter">
            {isPhysical ? 'Hardware' : 'Virtual'}
          </span>
          <div className={`w-2 h-2 rounded-full ${meterValue > 0.01 ? 'bg-green-400 led-green' : 'bg-gray-800'}`} />
        </div>

        {isPhysical ? (
            <div className="relative group/input">
                <button className="flex items-center justify-between w-full text-[9px] bg-black/40 p-1 rounded border border-transparent hover:border-[#444] truncate text-gray-300">
                    <span className="truncate flex-1 text-left">
                        {availableDevices.find(d => d.deviceId === settings.deviceId)?.label.substring(0, 15) || settings.name}
                    </span>
                    <ChevronDown size={8} />
                </button>
                <div className="absolute top-full left-0 w-48 bg-[#111] border border-[#444] z-50 hidden group-hover/input:block max-h-48 overflow-y-auto shadow-xl">
                    {availableDevices.map(device => (
                        <div 
                            key={device.deviceId} 
                            onClick={() => onSelectDevice(settings.id, device.deviceId)}
                            className="p-2 text-[9px] hover:bg-blue-900 cursor-pointer text-gray-300 truncate"
                        >
                            {device.label}
                        </div>
                    ))}
                </div>
            </div>
        ) : (
             <button 
                onClick={() => onSelectVirtual(settings.id)}
                className="w-full text-[9px] bg-blue-900/30 p-1 rounded border border-blue-900/50 hover:bg-blue-800/50 truncate text-blue-200 flex items-center justify-center gap-1"
            >
                <Monitor size={8} /> SELECT SOURCE
            </button>
        )}
      </div>

      {/* EQ Section */}
      <div className="p-3 space-y-2 flex-grow flex flex-col">
        <div className="space-y-2">
            <Knob 
                label="HIGH" 
                value={settings.eq.high} 
                onChange={(v) => onChange(settings.id, { eq: { ...settings.eq, high: v } })} 
            />
            <Knob 
                label="MID" 
                value={settings.eq.mid} 
                onChange={(v) => onChange(settings.id, { eq: { ...settings.eq, mid: v } })} 
            />
            <Knob 
                label="LOW" 
                value={settings.eq.low} 
                onChange={(v) => onChange(settings.id, { eq: { ...settings.eq, low: v } })} 
            />
        </div>

        {/* Dynamic Meter & Fader */}
        <div className="flex-grow flex justify-center py-2 relative min-h-[150px]">
          <div className="w-4 h-full bg-black rounded-sm border border-[#333] flex flex-col-reverse overflow-hidden relative">
             <div 
              className="w-full transition-all duration-75"
              style={{ 
                height: `${Math.min(100, meterValue * 100)}%`,
                backgroundColor: meterValue > 0.8 ? '#ef4444' : meterValue > 0.6 ? '#f59e0b' : color
              }} 
             />
             <div className="absolute top-0 w-full h-0.5 bg-red-500 opacity-30" />
          </div>

          <div className="absolute left-1/2 -translate-x-1/2 h-full flex items-center z-10">
             <input 
              type="range"
              min="0"
              max="2"
              step="0.01"
              value={settings.gain}
              onChange={handleGainChange}
              className="appearance-none h-[180px] w-8 bg-transparent cursor-pointer vertical-range"
              style={{
