import { ChannelSettings, MasterSettings, StripType } from '../types';

interface ChannelStripNodes {
  source: MediaStreamAudioSourceNode | null;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  gain: GainNode;
  meterNode: AnalyserNode;
  monitorGain: GainNode; // Used for monitoring toggle
}

class AudioEngine {
  private context: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private masterLimiter: DynamicsCompressorNode | null = null;
  private channels: ChannelStripNodes[] = [];
  private initialized = false;

  async initialize() {
    if (this.initialized) return;

    // Low latency context
    this.context = new (window.AudioContext || (window as any).webkitAudioContext)({
      latencyHint: 'interactive',
      sampleRate: 48000
    });

    // Master Bus Chain: MasterGain -> Limiter -> Destination
    this.masterGain = this.context.createGain();
    this.masterGain.gain.value = 1.0;

    // Brickwall Limiter to prevent clipping
    this.masterLimiter = this.context.createDynamicsCompressor();
    this.masterLimiter.threshold.value = -1.0;
    this.masterLimiter.knee.value = 0;
    this.masterLimiter.ratio.value = 20.0;
    this.masterLimiter.attack.value = 0.005;
    this.masterLimiter.release.value = 0.1;

    this.masterGain.connect(this.masterLimiter);
    this.masterLimiter.connect(this.context.destination);

    // Initialize Channel Strips
    for (let i = 0; i < 8; i++) {
      this.channels[i] = this.createChannelStrip();
    }

    this.initialized = true;
    console.log("Audio Engine Initialized: 48kHz, Low Latency, Limited Master");
  }

  private createChannelStrip(): ChannelStripNodes {
    if (!this.context) throw new Error("Context not initialized");

    const eqLow = this.context.createBiquadFilter();
    eqLow.type = 'lowshelf';
    eqLow.frequency.value = 80;

    const eqMid = this.context.createBiquadFilter();
    eqMid.type = 'peaking';
    eqMid.frequency.value = 2500;
    eqMid.Q.value = 1.0;

    const eqHigh = this.context.createBiquadFilter();
    eqHigh.type = 'highshelf';
    eqHigh.frequency.value = 12000;

    const gain = this.context.createGain();
    const monitorGain = this.context.createGain();
    const meterNode = this.context.createAnalyser();
    meterNode.fftSize = 256;
    meterNode.smoothingTimeConstant = 0.5;

    // Chain: Source -> Low -> Mid -> High -> Gain -> MonitorGain -> Master
    // Meter taps off before MonitorGain so you see levels even if muted/unmonitored (Pre-fader metering? usually post-fader but pre-mute. Let's do Post-Gain)

    eqLow.connect(eqMid);
    eqMid.connect(eqHigh);
    eqHigh.connect(gain);
    gain.connect(meterNode);
    gain.connect(monitorGain);
    monitorGain.connect(this.masterGain!);

    return {
      source: null,
      eqLow,
      eqMid,
      eqHigh,
      gain,
      meterNode,
      monitorGain
    };
  }

  async setInputDevice(id: number, deviceId: string) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      const audioConstraints: any = {
        echoCancellation: false,
        autoGainControl: false,
        noiseSuppression: false,
        latency: 0
      };

      // Only apply deviceId constraint if it's a valid non-empty string
      if (deviceId && deviceId.trim() !== "") {
        audioConstraints.deviceId = { exact: deviceId };
      }

      let stream: MediaStream;
      try {
          stream = await navigator.mediaDevices.getUserMedia({ 
            audio: audioConstraints
          });
      } catch (err: any) {
          // If exact device failed (e.g. unplugged), try fallback to default
          if (err.name === 'OverconstrainedError' || err.name === 'ConstraintNotSatisfiedError') {
              console.warn(`Device ${deviceId} not found, falling back to default.`);
              delete audioConstraints.deviceId;
              stream = await navigator.mediaDevices.getUserMedia({ 
                audio: audioConstraints
              });
          } else {
              throw err;
          }
      }

      strip.source = this.context.createMediaStreamSource(stream);
      strip.source.connect(strip.eqLow);
    } catch (err) {
      console.error(`Failed to connect device ${deviceId} to channel ${id}`, err);
    }
  }

  async setDisplayMedia(id: number) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      // @ts-ignore
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true });
      // We only care about audio. Note: User must check "Share Audio" in the browser dialog.
      if (stream.getAudioTracks().length > 0) {
        strip.source = this.context.createMediaStreamSource(stream);
        strip.source.connect(strip.eqLow);
      } else {
        alert("No audio track found. Please ensure 'Share Audio' is checked.");
      }
    } catch (err) {
      console.error("Display media selection cancelled or failed", err);
    }
  }

  // Fallback for default mic
  async startMic() {
    if (!this.context) return;
    // Default to first channel
    try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const audioInput = devices.find(d => d.kind === 'audioinput');
        if (audioInput) {
            await this.setInputDevice(0, audioInput.deviceId);
        }
    } catch(e) {
        console.error("Default mic error", e);
    }
  }

  updateChannel(id: number, settings: ChannelSettings) {
    if (!this.channels[id] || !this.context) return;
    const strip = this.channels[id];
    const now = this.context.currentTime;

    // Gain & Mute
    // Note: Mute overrides monitor in this logic, effectively silencing the channel strip
    const targetGain = settings.mute ? 0 : settings.gain;
    strip.gain.gain.setTargetAtTime(targetGain, now, 0.02);

    // Monitor Toggle (Routing to Master)
    // If Monitor is ON, we let sound through monitorGain to Master.
    // If Monitor is OFF, we mute monitorGain (effectively removing it from Main Mix), but Meter still works.
    // Solo logic is handled in App.tsx by muting non-soloed channels.
    const monitorVal = settings.monitor ? 1 : 0;
    strip.monitorGain.gain.setTargetAtTime(monitorVal, now, 0.02);

    // EQ
    strip.eqLow.gain.setTargetAtTime(settings.eq.low, now, 0.1);
    strip.eqMid.gain.setTargetAtTime(settings.eq.mid, now, 0.1);
    strip.eqHigh.gain.setTargetAtTime(settings.eq.high, now, 0.1);
  }

  setMasterVolume(volume: number) {
    if (this.masterGain && this.context) {
      this.masterGain.gain.setTargetAtTime(volume, this.context.currentTime, 0.05);
    }
  }

  getMeter(id: number): number {
    if (!this.channels[id]) return 0;
    const analyzer = this.channels[id].meterNode;
    const data = new Uint8Array(analyzer.frequencyBinCount);
    analyzer.getByteFrequencyData(data);

    // Simple RMS-ish approximation
    let sum = 0;
    for(let i=0; i<data.length; i++) {
        sum += data[i];
    }
    const avg = sum / data.length;
    return avg / 128; // Normalize 0-1ish
  }

  resume() {
    this.context?.resume();
  }

  // --- Health Monitor Diagnostics & Repair ---

  getContextState(): AudioContextState | 'uninitialized' {
    return this.context ? this.context.state : 'uninitialized';
  }

  getContextTime(): number {
    return this.context ? this.context.currentTime : 0;
  }

  async tryResumeContext() {
    if (this.context && this.context.state === 'suspended') {
      await this.context.resume();
    }
  }

  async restartContext() {
    if (this.context) {
      await this.context.close();
    }
    this.initialized = false;
    await this.initialize();
  }

  // Protocol A: Fallback to default device
  async switchChannelToDefault(id: number) {
    console.warn(`[AudioEngine] Switching channel ${id} to default fallback.`);
    await this.setInputDevice(id, ""); // Passing empty string triggers logic to use default
  }
}

