          solo: false,
          monitor: true, // Default to monitoring enabled
          pan: 0,
          eq: { low: 0, mid: 0, high: 0 },
          gate: { threshold: -60, active: false },
          compressor: { threshold: -20, ratio: 4, active: false },
          routing: [true, false, false, false, false, false, false, false]
        });
      }
      setChannels(initialChannels);
    };

    loadSettings();

    // Enumerate devices
    const updateDevices = () => {
        navigator.mediaDevices.enumerateDevices().then(devs => {
            setInputDevices(devs.filter(d => d.kind === 'audioinput'));
            // Note: 'audiooutput' is hidden by browser privacy sometimes until permission is granted
            setOutputDevices(devs.filter(d => d.kind === 'audiooutput'));
        });
    };

    updateDevices();
    navigator.mediaDevices.addEventListener('devicechange', updateDevices);
  }, []);

  // Save settings to localStorage
  useEffect(() => {
    if (channels.length > 0) {
      localStorage.setItem('omnimix_settings', JSON.stringify({ channels, masterSettings }));
      if (isInitialized) {
          audioHealthMonitor.updateChannels(channels);
      }
    }
  }, [channels, masterSettings, isInitialized]);

  // Sync master settings to audio engine
  useEffect(() => {
    if (isInitialized) {
      audioEngine.setMasterSettings(masterSettings);
    }
  }, [masterSettings, isInitialized]);

  // Monitor Setup
  useEffect(() => {
    if (isInitialized) {
        audioHealthMonitor.onHealthUpdate = setHealthReport;
        audioHealthMonitor.start(channels);
    }
    return () => {
        audioHealthMonitor.stop();
    };
  }, [isInitialized]);

  const handleInitialize = async () => {
    await audioEngine.initialize();

    // Refresh device list after permission grant (often output devices appear then)
    const devs = await navigator.mediaDevices.enumerateDevices();
    setInputDevices(devs.filter(d => d.kind === 'audioinput'));
    setOutputDevices(devs.filter(d => d.kind === 'audiooutput'));

    // Connect initial devices if saved
    for (const ch of channels) {
        if (ch.type === StripType.PHYSICAL && ch.deviceId) {
            await audioEngine.setInputDevice(ch.id, ch.deviceId);
        } else if (ch.type === StripType.PHYSICAL && !ch.deviceId && devs.length > 0) {
             const audioInputs = devs.filter(d => d.kind === 'audioinput');
             if (ch.id === 0 && audioInputs.length > 0) {
                await audioEngine.setInputDevice(0, audioInputs[0].deviceId);
            }
        }
    }

    // Apply Master Settings
    audioEngine.setMasterSettings(masterSettings);

    // Sync state to engine
    const anySolo = channels.some(ch => ch.solo);
    channels.forEach(ch => {
        const effectiveMute = anySolo ? !ch.solo : ch.mute;
        audioEngine.updateChannel(ch.id, { ...ch, mute: effectiveMute });
    });

    setIsInitialized(true);
  };

  const handleDeviceSelect = async (id: number, deviceId: string) => {
      updateChannel(id, { deviceId });
      if (isInitialized) {
          await audioEngine.setInputDevice(id, deviceId);
      }
  };

  const handleVirtualSelect = async (id: number) => {
      if (isInitialized) {
          await audioEngine.setDisplayMedia(id);
      }
  };

  const updateChannel = (id: number, settings: Partial<ChannelSettings>) => {
    setChannels(prev => {
      const updated = [...prev];
      updated[id] = { ...updated[id], ...settings };
      if (isInitialized) {
        const anySolo = updated.some(ch => ch.solo);
        updated.forEach(ch => {
            const effectiveMute = anySolo ? !ch.solo : ch.mute;
            audioEngine.updateChannel(ch.id, { ...ch, mute: effectiveMute });
        });
      }
      return updated;
    });
  };

  useEffect(() => {
    if (!isInitialized) return;
    const interval = setInterval(() => {
      setMeters(channels.map((_, i) => audioEngine.getMeter(i)));
    }, 50);
    return () => clearInterval(interval);
  }, [isInitialized, channels]);

  const runAiOptimization = async () => {
    setAiLoading(true);
    const advice = await getGeminiOptimization("Vocal Mic", "Physical XLR");
    setAiAdvice(advice || "No advice available.");
    setAiLoading(false);
  };

  // Menu Handlers
  const handleMenuClick = (action: string) => {
      alert(`${action} menu feature is not yet implemented in this web simulation.`);
  };

  if (!isInitialized) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#0a0a0a] text-white p-6">
        <div className="max-w-md w-full bg-[#1a1a1a] p-8 rounded-lg border border-[#333] shadow-2xl flex flex-col items-center space-y-6 text-center">
          <div className="w-20 h-20 bg-blue-600 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(37,99,235,0.4)]">
            <ShieldCheck size={48} className="text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-black italic tracking-tight mb-2 uppercase">OMNIMIX ENGINE</h1>
            <p className="text-gray-400 text-sm leading-relaxed">
              To simulate the requested 5.1/7.1 matrix and low-latency WDM drivers, we must initialize the Web Audio context. 
              <br/><br/>
              <span className="text-yellow-500/80 font-bold flex items-center justify-center gap-1">
                <AlertTriangle size={14} /> KERNEL MODE SIMULATION ACTIVE
              </span>
            </p>
          </div>
          <button 
            onClick={handleInitialize}
            className="w-full py-4 bg-white text-black font-black uppercase tracking-widest rounded hover:bg-gray-200 transition-all transform active:scale-95"
          >
            Engage Audio Engine
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen flex flex-col bg-[#121212] select-none">
      {/* Top Header Bar */}
      <div className="bg-[#1a1a1a] border-b border-[#333] p-2 flex justify-between items-center">
