            <button onClick={() => handleMenuClick("SYSTEM")} className="hover:text-white transition-colors">SYSTEM</button>
          </div>
        </div>
        <div className="flex items-center gap-4">
           {/* Health Indicator */}
           <div className={`flex items-center gap-2 px-2 py-1 rounded border ${healthReport.status === HealthStatus.HEALTHY ? 'border-green-900 bg-green-900/20' : 'border-red-900 bg-red-900/20'}`}>
              <HeartPulse size={12} className={healthReport.status === HealthStatus.HEALTHY ? 'text-green-500' : 'text-red-500 animate-pulse'} />
