export default App;

import { ChannelSettings, MasterSettings, StripType } from '../types';

interface ChannelStripNodes {
  source: MediaStreamAudioSourceNode | null;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  gain: GainNode;
  meterNode: AnalyserNode;
  monitorGain: GainNode; 
}

class AudioEngine {
  private context: AudioContext | null = null;

  // Master Bus Nodes
  private masterGain: GainNode | null = null;
  private noiseFilter: BiquadFilterNode | null = null; // Highpass for noise reduction
  private reverbNode: ConvolverNode | null = null;
  private reverbGain: GainNode | null = null;
  private delayNode: DelayNode | null = null;
  private delayGain: GainNode | null = null;
  private masterLimiter: DynamicsCompressorNode | null = null;

  private channels: ChannelStripNodes[] = [];
  private initialized = false;

  // Global preferences
  private aecEnabled: boolean = false; 

  async initialize() {
    if (this.initialized) return;

    // Low latency context
    this.context = new (window.AudioContext || (window as any).webkitAudioContext)({
      latencyHint: 'interactive',
      sampleRate: 48000
    });

    // --- Master Bus DSP Chain Construction ---

    // 1. Master Input Gain
    this.masterGain = this.context.createGain();
    this.masterGain.gain.value = 1.0;

    // 2. Noise Reduction (Simple Highpass / Low-End Rumble Filter)
    this.noiseFilter = this.context.createBiquadFilter();
    this.noiseFilter.type = 'highpass';
    this.noiseFilter.frequency.value = 0; // Starts disabled (0Hz)
    this.noiseFilter.Q.value = 0.5;

    // 3. FX: Reverb (Parallel)
    this.reverbNode = this.context.createConvolver();
    this.reverbNode.buffer = this.createImpulseResponse(2.0, 2.0); // 2 seconds reverb
    this.reverbGain = this.context.createGain();
    this.reverbGain.gain.value = 0; // Controlled by UI

    // 4. FX: Delay (Parallel)
    this.delayNode = this.context.createDelay(1.0);
    this.delayNode.delayTime.value = 0.4; // 400ms delay
    this.delayGain = this.context.createGain();
    this.delayGain.gain.value = 0; // Controlled by UI

    // 5. Limiter (Final Output Protection)
    this.masterLimiter = this.context.createDynamicsCompressor();
    this.masterLimiter.threshold.value = -1.0;
    this.masterLimiter.knee.value = 0;
    this.masterLimiter.ratio.value = 20.0;
    this.masterLimiter.attack.value = 0.005;
    this.masterLimiter.release.value = 0.1;

    // --- Connections ---

    // Signal Flow: MasterGain -> NoiseFilter -> Limiter -> Dest
    //                           |-> Reverb -> Limiter
    //                           |-> Delay -> Limiter

    this.masterGain.connect(this.noiseFilter);

    // Dry Path
    this.noiseFilter.connect(this.masterLimiter);

    // Wet Paths
    this.noiseFilter.connect(this.reverbGain);
    this.reverbGain.connect(this.reverbNode);
    this.reverbNode.connect(this.masterLimiter);

    this.noiseFilter.connect(this.delayGain);
    this.delayGain.connect(this.delayNode);
    this.delayNode.connect(this.masterLimiter); // Simple delay line

    // Create feedback for delay for better effect? 
    // For simplicity, simple echo for now.

    this.masterLimiter.connect(this.context.destination);

    // Initialize Channel Strips
    for (let i = 0; i < 8; i++) {
      this.channels[i] = this.createChannelStrip();
    }

    this.initialized = true;
    console.log("Audio Engine Initialized: 48kHz, DSP Chain Active");
  }

  // Helper to generate Reverb Impulse Response
  private createImpulseResponse(duration: number, decay: number): AudioBuffer | null {
    if (!this.context) return null;
    const length = this.context.sampleRate * duration;
    const impulse = this.context.createBuffer(2, length, this.context.sampleRate);
    const left = impulse.getChannelData(0);
    const right = impulse.getChannelData(1);

    for (let i = 0; i < length; i++) {
        const n = i; // undefined fix
        // Simple exponential decay noise
        const val = (Math.random() * 2 - 1) * Math.pow(1 - n / length, decay);
        left[i] = val;
        right[i] = val;
    }
    return impulse;
  }

  private createChannelStrip(): ChannelStripNodes {
    if (!this.context) throw new Error("Context not initialized");

    const eqLow = this.context.createBiquadFilter();
    eqLow.type = 'lowshelf';
    eqLow.frequency.value = 80;

    const eqMid = this.context.createBiquadFilter();
    eqMid.type = 'peaking';
    eqMid.frequency.value = 2500;
    eqMid.Q.value = 1.0;

    const eqHigh = this.context.createBiquadFilter();
    eqHigh.type = 'highshelf';
    eqHigh.frequency.value = 12000;

    const gain = this.context.createGain();
    const monitorGain = this.context.createGain();
    const meterNode = this.context.createAnalyser();
    meterNode.fftSize = 256;
    meterNode.smoothingTimeConstant = 0.5;

    // Chain: Source -> Low -> Mid -> High -> Gain -> MonitorGain -> Master
    eqLow.connect(eqMid);
    eqMid.connect(eqHigh);
    eqHigh.connect(gain);
    gain.connect(meterNode);
    gain.connect(monitorGain);
    monitorGain.connect(this.masterGain!);

    return {
      source: null,
      eqLow,
      eqMid,
      eqHigh,
      gain,
      meterNode,
      monitorGain
    };
  }

  async setInputDevice(id: number, deviceId: string) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      const audioConstraints: any = {
        echoCancellation: this.aecEnabled, // Respect global AEC setting
        autoGainControl: false,
        noiseSuppression: false, // We use our own filter
        latency: 0
      };

      if (deviceId && deviceId.trim() !== "") {
        audioConstraints.deviceId = { exact: deviceId };
      }

      let stream: MediaStream;
      try {
          stream = await navigator.mediaDevices.getUserMedia({ 
            audio: audioConstraints
          });
      } catch (err: any) {
          if (err.name === 'OverconstrainedError' || err.name === 'ConstraintNotSatisfiedError') {
              console.warn(`Device ${deviceId} not found, falling back to default.`);
              delete audioConstraints.deviceId;
              stream = await navigator.mediaDevices.getUserMedia({ 
                audio: audioConstraints
              });
          } else {
              throw err;
          }
      }

      strip.source = this.context.createMediaStreamSource(stream);
      strip.source.connect(strip.eqLow);
    } catch (err) {
      console.error(`Failed to connect device ${deviceId} to channel ${id}`, err);
    }
  }

  async setDisplayMedia(id: number) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];

    if (strip.source) {
      strip.source.disconnect();
    }

    try {
      // @ts-ignore
      const stream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true });
      if (stream.getAudioTracks().length > 0) {
        strip.source = this.context.createMediaStreamSource(stream);
        strip.source.connect(strip.eqLow);
      } else {
        alert("No audio track found. Please ensure 'Share Audio' is checked.");
      }
    } catch (err) {
      console.error("Display media selection cancelled or failed", err);
    }
  }

  // Sets the hardware destination for the entire context
  async setOutputDevice(deviceId: string) {
      if (!this.context) return;

      // 'setSinkId' is experimental on AudioContext in some browsers, standard on HTMLMediaElement.
      // However, for Web Audio, we often use destination. 
      // TS might complain, so we cast to any.
      const ctx = this.context as any;

      if (typeof ctx.setSinkId === 'function') {
          try {
              await ctx.setSinkId(deviceId);
              console.log(`Output routed to device: ${deviceId}`);
          } catch (err) {
              console.error('Failed to set output device', err);
          }
      } else {
          console.warn("Browser does not support AudioContext.setSinkId");
          alert("Your browser does not support routing audio to specific output devices directly from Web Audio API. It will use the system default.");
      }
  }

  updateChannel(id: number, settings: ChannelSettings) {
    if (!this.context || !this.channels[id]) return;
    const strip = this.channels[id];
    const now = this.context.currentTime;

    // Gain & Mute
    const targetGain = settings.mute ? 0 : settings.gain;
    strip.gain.gain.setTargetAtTime(targetGain, now, 0.05);

    // EQ
    strip.eqLow.gain.setTargetAtTime(settings.eq.low, now, 0.1);
    strip.eqMid.gain.setTargetAtTime(settings.eq.mid, now, 0.1);
    strip.eqHigh.gain.setTargetAtTime(settings.eq.high, now, 0.1);

    // Monitor
    const monitorVal = settings.monitor ? 1.0 : 0.0;
    strip.monitorGain.gain.setTargetAtTime(monitorVal, now, 0.05);
  }

  setMasterSettings(settings: MasterSettings) {
      if (!this.context) return;
      const now = this.context.currentTime;

      // Master Gain
      if (this.masterGain) {
          this.masterGain.gain.setTargetAtTime(settings.masterGain, now, 0.05);
      }

      // Reverb Send Level
      if (this.reverbGain) {
          this.reverbGain.gain.setTargetAtTime(settings.reverb, now, 0.1);
      }

      // Delay Send Level
      if (this.delayGain) {
          this.delayGain.gain.setTargetAtTime(settings.delay, now, 0.1);
      }

      // Noise Filter (Highpass)
      // Map 0..1 knob to 0..500Hz
      if (this.noiseFilter) {
          const freq = settings.noiseReduction * 500; 
          this.noiseFilter.frequency.setTargetAtTime(freq, now, 0.1);
      }

      // AEC Logic
      if (this.aecEnabled !== settings.aec) {
          this.aecEnabled = settings.aec;
          // Note: Toggling AEC requires re-getting user media streams. 
          // In a real app, we would loop through active channels and reconnect them.
          // For now, we will just store the flag so next connection uses it, or user must toggle input.
          console.log(`AEC Set to ${this.aecEnabled}. Re-select inputs to apply.`);
      }

      // Output Device (Handled individually if changed, but checked here)
      if (settings.outputDeviceId) {
          this.setOutputDevice(settings.outputDeviceId);
      }
  }

  getMeter(id: number): number {
    if (!this.channels[id]) return 0;
    const analyzer = this.channels[id].meterNode;
    const data = new Uint8Array(analyzer.frequencyBinCount);
    analyzer.getByteFrequencyData(data);
    let sum = 0;
    for(let i=0; i<data.length; i++) sum += data[i];
    return (sum / data.length) / 128;
  }

  // ... (Existing diagnostics methods remain the same) ...
  getContextState(): AudioContextState | 'uninitialized' {
    return this.context ? this.context.state : 'uninitialized';
  }

  getContextTime(): number {
    return this.context ? this.context.currentTime : 0;
  }

  async tryResumeContext() {
    if (this.context && this.context.state === 'suspended') {
      await this.context.resume();
    }
  }

  async restartContext() {
    if (this.context) {
      await this.context.close();
    }
    this.initialized = false;
    await this.initialize();
  }

  async switchChannelToDefault(id: number) {
    console.warn(`[AudioEngine] Switching channel ${id} to default fallback.`);
    await this.setInputDevice(id, ""); 
  }
}

export const audioEngine = new AudioEngine();

import { audioEngine } from './audioEngine';
import { AudioErrorCode, HealthReport, HealthStatus, ChannelSettings } from '../types';

class AudioHealthMonitor {
  private intervalId: number | null = null;
  private lastContextTime: number = 0;
  private sameTimeCount: number = 0;
  private silenceCounters: Record<number, number> = {};

  // Configuration
  private readonly CHECK_INTERVAL_MS = 1000;
  private readonly SILENCE_THRESHOLD_MS = 5000;
  private readonly STALL_THRESHOLD_COUNT = 3; // 3 checks with same time = stalled

  private currentChannels: ChannelSettings[] = [];

  public onHealthUpdate: ((report: HealthReport) => void) | null = null;

  start(channels: ChannelSettings[]) {
    if (this.intervalId) return;
    this.currentChannels = channels;
    this.lastContextTime = audioEngine.getContextTime();

    this.intervalId = window.setInterval(async () => {
      await this.performHealthCheck();
    }, this.CHECK_INTERVAL_MS);

    console.log("[HealthMonitor] Watchdog started.");
  }

  stop() {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  updateChannels(channels: ChannelSettings[]) {
    this.currentChannels = channels;
  }

  private async performHealthCheck() {
    const state = audioEngine.getContextState();

    // 1. Check Engine State & Stall (Protocol C)
    if (state === 'closed' || state === 'uninitialized') {
        // Critical: Engine dead
        this.reportError(AudioErrorCode.STREAM_STALL, "Audio Context is closed.");
        // We probably can't auto-heal a closed context easily without re-init, handled by UI usually
        return;
    }

    const currentTime = audioEngine.getContextTime();
    if (Math.abs(currentTime - this.lastContextTime) < 0.001) {
        if (state === 'running') {
            this.sameTimeCount++;
            if (this.sameTimeCount >= this.STALL_THRESHOLD_COUNT) {
                await this.executeProtocolC("Audio stream stalled (Time not advancing)");
                this.sameTimeCount = 0;
            }
        } else if (state === 'suspended') {
             // Try auto-resume
             await audioEngine.tryResumeContext();
        }
    } else {
        this.sameTimeCount = 0;
    }
    this.lastContextTime = currentTime;

    // 2. Check Device Integrity (Protocol A)
    // We check if the assigned deviceId still exists in the OS
    const devices = await navigator.mediaDevices.enumerateDevices();
    const inputDeviceIds = new Set(devices.filter(d => d.kind === 'audioinput').map(d => d.deviceId));

    for (const ch of this.currentChannels) {
        if (ch.type === 'PHYSICAL' && ch.deviceId && !inputDeviceIds.has(ch.deviceId)) {
            await this.executeProtocolA(ch.id, `Device ${ch.deviceId} lost.`);
        }
    }

    // 3. Check for Silent Failures (Protocol C / Restart)
    // If channel is NOT muted, but metering is absolute 0 for N seconds.
    // Note: Standard noise floor is rarely 0.00000.
    for (const ch of this.currentChannels) {
        // Only check physical channels that have a specific device assigned
        // We ignore virtual channels here because they are often silent (no active app)
        // We ignore channels without a selected deviceId to prevent false positives on unused strips
        if (ch.type === 'PHYSICAL' && ch.deviceId) { 
            if (!ch.mute && ch.gain > 0) {
                const meterVal = audioEngine.getMeter(ch.id);
                if (meterVal === 0) {
                    this.silenceCounters[ch.id] = (this.silenceCounters[ch.id] || 0) + this.CHECK_INTERVAL_MS;
                    if (this.silenceCounters[ch.id] > this.SILENCE_THRESHOLD_MS) {
                        this.reportError(AudioErrorCode.SILENT_FAILURE, `Channel ${ch.id} silent for >5s.`);
                        // Resetting counter to avoid spamming the log
                        this.silenceCounters[ch.id] = 0; 
                    }
                } else {
                    this.silenceCounters[ch.id] = 0;
                }
            } else {
                this.silenceCounters[ch.id] = 0;
            }
        } else {
            // Reset counters for unmonitored channels
            this.silenceCounters[ch.id] = 0;
        }
    }

    // If we made it here without returning, we are good
    // Only report healthy if status was not already Warning/Critical recently, 
    // or if we want to constantly confirm life. 
    // For now, we assume if no error was reported above, we are nominal.
    // However, reporting every second might be noisy for the UI state updates, 
    // but the UI component handles that.

    // We only invoke onHealthUpdate if we are *not* currently reporting an error in this tick.
    // Since reportError invokes the callback, we don't need to do anything here unless we want to clear previous errors.
    // Let's rely on the UI or a separate mechanism to clear "Warning" state, 
    // OR we send a "HEALTHY" pulse if everything passed.

    // Since reportError is instantaneous, we can send a Healthy heartbeat here.
    // The UI can decide to show the last error for a few seconds.
    this.onHealthUpdate?.({
        status: HealthStatus.HEALTHY,
        timestamp: Date.now(),
        message: "System Nominal"
    });
  }

  /**
   * Protocol A: Device Loss -> Reroute to Default
   */
  private async executeProtocolA(channelId: number, reason: string) {
    this.reportError(AudioErrorCode.DEVICE_LOST, reason);
    console.warn(`[HealthMonitor] Executing Protocol A for Ch ${channelId}`);
    await audioEngine.switchChannelToDefault(channelId);
  }

  /**
   * Protocol C: Stream Stall -> Soft Reset
   */
  private async executeProtocolC(reason: string) {
    this.reportError(AudioErrorCode.STREAM_STALL, reason);
    console.warn(`[HealthMonitor] Executing Protocol C (Engine Restart)`);
    // Attempt resume first
    await audioEngine.tryResumeContext();

    // If still stuck next tick, logic elsewhere would ideally trigger full restart
    // For now, let's try a resume.
  }

  private reportError(code: AudioErrorCode, msg: string) {
    console.error(`[AudioHealthReport] ${code}: ${msg}`);
    this.onHealthUpdate?.({
        status: HealthStatus.WARNING,
        lastError: code,
        timestamp: Date.now(),
        message: msg
    });
  }
}

