  onOptimize: () => void;
}

const Knob = ({ value, onChange, label, min, max, color = "blue", size = "w-10 h-10" }: any) => {
    const [isDragging, setIsDragging] = useState(false);
    const startY = useRef(0);
    const startVal = useRef(0);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging) return;
            const deltaY = startY.current - e.clientY;
            const range = max - min;
            let newVal = startVal.current + deltaY * (range / 200);
            newVal = Math.max(min, Math.min(max, newVal));
            onChange(newVal);
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, onChange, min, max]);

    const percentage = (value - min) / (max - min);
    const rotation = (percentage * 270) - 135;

    const indicatorColor = color === "green" ? "bg-green-500" : color === "red" ? "bg-red-500" : "bg-blue-500";

    return (
        <div className="flex flex-col items-center gap-1">
            <div 
                className={`${size} rounded-full skeuo-knob flex items-center justify-center relative cursor-ns-resize group`}
                onMouseDown={(e) => {
                    setIsDragging(true);
                    startY.current = e.clientY;
                    startVal.current = value;
                }}
            >
              <div 
                className={`absolute w-0.5 h-1/2 ${indicatorColor} rounded-full origin-bottom top-[10%] transition-transform duration-75`} 
                style={{ transform: `rotate(${rotation}deg) translateY(-50%)` }}
              />
            </div>
            {label && <span className="text-[8px] font-bold text-gray-500 uppercase">{label}</span>}
        </div>
    );
};

