import React, { useEffect, useState } from 'react';
import { TOTAL_INPUTS, CHANNEL_COLORS } from './constants';
import { ChannelSettings, MasterSettings, StripType } from './types';
import MixerStrip from './components/MixerStrip';
import MasterSection from './components/MasterSection';
import VbanPanel from './components/VbanPanel';
import DriverModal from './components/DriverModal';
import { audioEngine } from './services/audioEngine';
import { audioHealthMonitor } from './services/AudioHealthMonitor';
import { getGeminiOptimization } from './services/geminiService';

const INITIAL_CHANNELS: ChannelSettings[] = Array.from({ length: TOTAL_INPUTS }, (_, i) => ({
  id: i + 1,
  name: `CH ${i + 1}`,
  type: i < 5 ? StripType.PHYSICAL : StripType.VIRTUAL,
  gain: 1,
  mute: false,
  solo: false,
  monitor: false,
  pan: 0,
  eq: { low: 0, mid: 0, high: 0 },
  gate: { threshold: -60, active: false },
  compressor: { threshold: -20, ratio: 1, active: false },
  routing: [],
}));

const App: React.FC = () => {
  const [channels, setChannels] = useState<ChannelSettings[]>(INITIAL_CHANNELS);
  const [masterSettings, setMasterSettings] = useState<MasterSettings>({
    reverb: 0, delay: 0, noiseReduction: 0, aec: false, masterGain: 0.8
  });
  const [inputDevices, setInputDevices] = useState<MediaDeviceInfo[]>([]);
  const [outputDevices, setOutputDevices] = useState<MediaDeviceInfo[]>([]);
  const [isDriverModalOpen, setDriverModalOpen] = useState(false);

  useEffect(() => {
    const init = async () => {
      await audioEngine.initialize();
      const devices = await navigator.mediaDevices.enumerateDevices();
      setInputDevices(devices.filter(d => d.kind === 'audioinput'));
      setOutputDevices(devices.filter(d => d.kind === 'audiooutput'));

      // Initialize channels in engine
      INITIAL_CHANNELS.forEach(ch => audioEngine.createChannelStrip(ch.id));

      audioHealthMonitor.start(INITIAL_CHANNELS);
      audioHealthMonitor.onHealthUpdate = (report) => {
          // Log health but don't spam UI for now
          if (report.status !== 'HEALTHY') console.warn(report);
      };
    };
    init();
    return () => audioHealthMonitor.stop();
  }, []);

  useEffect(() => {
      audioHealthMonitor.updateChannels(channels);
      channels.forEach(ch => audioEngine.updateChannel(ch));
  }, [channels]);

  useEffect(() => {
      audioEngine.updateMaster(masterSettings);
  }, [masterSettings]);

  const handleChannelChange = (updated: ChannelSettings) => {
    setChannels(prev => prev.map(ch => ch.id === updated.id ? updated : ch));
  };

  const handleOptimization = async (channelId: number) => {
     const ch = channels.find(c => c.id === channelId);
     if(!ch) return;
     const suggestion = await getGeminiOptimization(ch.name, ch.type);
     alert(`AI Optimization Suggestion:\n${suggestion}`);
     // In a real app, we would parse this and apply it automatically.
  };

  const handleDriverRestart = async (settings: {bufferSize: number, sampleRate: number}) => {
      console.log("Rebooting Kernel with settings:", settings);
      await audioEngine.initialize(settings.bufferSize / 48000, settings.sampleRate);
      // Re-initialize strips
      channels.forEach(ch => {
          audioEngine.createChannelStrip(ch.id);
          audioEngine.setInputDevice(ch.id, ch.deviceId || '');
          audioEngine.updateChannel(ch);
      });
  };

  return (
    <div className="flex flex-col h-screen bg-[#121212] text-white overflow-hidden">

      {/* Menu / Top Bar - Hidden trigger for driver modal via 'Settings' text or logo could be added here */}

      <div className="flex-grow flex overflow-hidden">
        {/* Channel Strips Area */}
        <div className="flex-grow overflow-x-auto">
          <div className="flex h-full min-w-max">
            {channels.map((ch) => (
              <MixerStrip 
                key={ch.id} 
                settings={ch} 
                onChange={handleChannelChange} 
                inputDevices={inputDevices}
                onOptimize={() => handleOptimization(ch.id)}
              />
            ))}
          </div>
        </div>

        {/* Master Section */}
        <MasterSection 
          settings={masterSettings} 
          onChange={setMasterSettings} 
          outputDevices={outputDevices}
          onOptimize={() => handleOptimization(1)} // Just a dummy trigger
        />
      </div>

      {/* Footer / VBAN / Driver Status */}
      <div onClick={() => setDriverModalOpen(true)} className="cursor-pointer hover:bg-white/5 transition-colors">
        <VbanPanel />
      </div>

      <DriverModal 
        isOpen={isDriverModalOpen}
        onClose={() => setDriverModalOpen(false)}
        onSave={handleDriverRestart}
      />
    </div>
  );
};

export default App;

import { audioEngine } from './audioEngine';
import { AudioErrorCode, HealthReport, HealthStatus, ChannelSettings } from '../types';

class AudioHealthMonitor {
  private intervalId: number | null = null;
  private lastContextTime: number = 0;
  private sameTimeCount: number = 0;
  private silenceCounters: Record<number, number> = {};

  // Configuration
  private readonly CHECK_INTERVAL_MS = 1000;
  private readonly SILENCE_THRESHOLD_MS = 5000;
  private readonly STALL_THRESHOLD_COUNT = 3; // 3 checks with same time = stalled

  private currentChannels: ChannelSettings[] = [];

  public onHealthUpdate: ((report: HealthReport) => void) | null = null;

  start(channels: ChannelSettings[]) {
    if (this.intervalId) return;
    this.currentChannels = channels;
    this.lastContextTime = audioEngine.getContextTime();

    this.intervalId = window.setInterval(async () => {
      await this.performHealthCheck();
    }, this.CHECK_INTERVAL_MS);

    console.log("[HealthMonitor] Watchdog started.");
  }

  stop() {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  updateChannels(channels: ChannelSettings[]) {
    this.currentChannels = channels;
  }

  private async performHealthCheck() {
    const state = audioEngine.getContextState();

    // 1. Check Engine State & Stall (Protocol C)
    if (state === 'closed' || state === 'uninitialized') {
        // Critical: Engine dead
        this.reportError(AudioErrorCode.STREAM_STALL, "Audio Context is closed.");
        // We probably can't auto-heal a closed context easily without re-init, handled by UI usually
        return;
    }

    const currentTime = audioEngine.getContextTime();
    if (Math.abs(currentTime - this.lastContextTime) < 0.001) {
        if (state === 'running') {
            this.sameTimeCount++;
            if (this.sameTimeCount >= this.STALL_THRESHOLD_COUNT) {
                await this.executeProtocolC("Audio stream stalled (Time not advancing)");
                this.sameTimeCount = 0;
            }
        } else if (state === 'suspended') {
             // Try auto-resume
             await audioEngine.tryResumeContext();
        }
    } else {
        this.sameTimeCount = 0;
    }
    this.lastContextTime = currentTime;

    // 2. Check Device Integrity (Protocol A)
    // We check if the assigned deviceId still exists in the OS
    const devices = await navigator.mediaDevices.enumerateDevices();
    const inputDeviceIds = new Set(devices.filter(d => d.kind === 'audioinput').map(d => d.deviceId));

    for (const ch of this.currentChannels) {
        if (ch.type === 'PHYSICAL' && ch.deviceId && !inputDeviceIds.has(ch.deviceId)) {
            await this.executeProtocolA(ch.id, `Device ${ch.deviceId} lost.`);
        }
    }

    // 3. Check for Silent Failures (Protocol C / Restart)
    // If channel is NOT muted, but metering is absolute 0 for N seconds.
    // Note: Standard noise floor is rarely 0.00000.
    for (const ch of this.currentChannels) {
        // Only check physical channels that have a specific device assigned
        // We ignore virtual channels here because they are often silent (no active app)
        // We ignore channels without a selected deviceId to prevent false positives on unused strips
        if (ch.type === 'PHYSICAL' && ch.deviceId) { 
            if (!ch.mute && ch.gain > 0) {
                const meterVal = audioEngine.getMeter(ch.id);
                if (meterVal.peak === 0) {
                    this.silenceCounters[ch.id] = (this.silenceCounters[ch.id] || 0) + this.CHECK_INTERVAL_MS;
                    if (this.silenceCounters[ch.id] > this.SILENCE_THRESHOLD_MS) {
                        this.reportError(AudioErrorCode.SILENT_FAILURE, `Channel ${ch.id} silent for >5s.`);
                        // Resetting counter to avoid spamming the log
                        this.silenceCounters[ch.id] = 0; 
                    }
                } else {
                    this.silenceCounters[ch.id] = 0;
                }
            } else {
                this.silenceCounters[ch.id] = 0;
            }
        } else {
            // Reset counters for unmonitored channels
            this.silenceCounters[ch.id] = 0;
        }
    }

    // If we made it here without returning, we are good
    // Only report healthy if status was not already Warning/Critical recently, 
    // or if we want to constantly confirm life. 
    // For now, we assume if no error was reported above, we are nominal.
    // However, reporting every second might be noisy for the UI state updates, 
    // but the UI component handles that.

    // We only invoke onHealthUpdate if we are *not* currently reporting an error in this tick.
    // Since reportError invokes the callback, we don't need to do anything here unless we want to clear previous errors.
    // Let's rely on the UI or a separate mechanism to clear "Warning" state, 
    // OR we send a "HEALTHY" pulse if everything passed.

    // Since reportError is instantaneous, we can send a Healthy heartbeat here.
    // The UI can decide to show the last error for a few seconds.
    this.onHealthUpdate?.({
        status: HealthStatus.HEALTHY,
        timestamp: Date.now(),
        message: "System Nominal"
    });
  }

  /**
   * Protocol A: Device Loss -> Reroute to Default
   */
  private async executeProtocolA(channelId: number, reason: string) {
    this.reportError(AudioErrorCode.DEVICE_LOST, reason);
    console.warn(`[HealthMonitor] Executing Protocol A for Ch ${channelId}`);
    await audioEngine.switchChannelToDefault(channelId);
  }

  /**
   * Protocol C: Stream Stall -> Soft Reset
   */
  private async executeProtocolC(reason: string) {
    this.reportError(AudioErrorCode.STREAM_STALL, reason);
    console.warn(`[HealthMonitor] Executing Protocol C (Engine Restart)`);
    // Attempt resume first
    await audioEngine.tryResumeContext();

    // If still stuck next tick, logic elsewhere would ideally trigger full restart
    // For now, let's try a resume.
  }

  private reportError(code: AudioErrorCode, msg: string) {
    console.error(`[AudioHealthReport] ${code}: ${msg}`);
    this.onHealthUpdate?.({
        status: HealthStatus.WARNING,
        lastError: code,
        timestamp: Date.now(),
        message: msg
    });
  }
}

export const audioHealthMonitor = new AudioHealthMonitor();

import { ChannelSettings, MasterSettings, AudioMeterData } from '../types';

// --- Multithreaded AudioWorklet Code (Injected as Blob) ---
const GATE_PROCESSOR_CODE = `
class OmniGateProcessor extends AudioWorkletProcessor {
  constructor() {
    super();
    this.envelope = 0;
    this.sampleRate = 48000; 
  }

  static get parameterDescriptors() {
    return [
        {name: 'threshold', defaultValue: -100, minValue: -100, maxValue: 0},
        {name: 'bypass', defaultValue: 1, minValue: 0, maxValue: 1}
    ];
  }

  process(inputs, outputs, parameters) {
    const input = inputs[0];
    const output = outputs[0];
    const thresholdDB = parameters.threshold[0];
    const bypass = parameters.bypass[0] > 0.5;

    // If bypassed, copy input to output directly
    if (bypass) {
        if (input && output) {
             for (let c = 0; c < input.length; ++c) {
                 if (output[c]) output[c].set(input[c]);
             }
        }
        return true;
    }

    if (!input || input.length === 0) return true;

    const thresholdLinear = Math.pow(10, thresholdDB / 20);
    const attack = 0.003; // Fast attack
    const release = 0.1;  // Smooth release

    for (let c = 0; c < input.length; ++c) {
        const inputData = input[c];
        const outputData = output[c];

        if (!inputData || !outputData) continue;

        for (let i = 0; i < inputData.length; ++i) {
            const lvl = Math.abs(inputData[i]);

            // Envelope Follower
            if (lvl > this.envelope) {
                this.envelope += (lvl - this.envelope) * attack;
            } else {
                this.envelope += (lvl - this.envelope) * (attack / 10);
            }

            // Gate Logic
            let gain = 0;
            if (this.envelope > thresholdLinear) {
                gain = 1.0;
            } else {
                gain = 0.0; 
            }

            outputData[i] = inputData[i] * gain;
        }
    }
    return true;
  }
}
registerProcessor('omni-gate', OmniGateProcessor);
`;

interface ChannelStripNodes {
  source: MediaStreamAudioSourceNode | null;
  gateNode: AudioWorkletNode | null;
  compressorNode: DynamicsCompressorNode;
  eqLow: BiquadFilterNode;
  eqMid: BiquadFilterNode;
  eqHigh: BiquadFilterNode;
  panNode: StereoPannerNode;
  gainNode: GainNode;
  meterNode: AnalyserNode;
  stream: MediaStream | null;
}

class AudioEngine {
  private context: AudioContext | null = null;
  private channels: Map<number, ChannelStripNodes> = new Map();
  private masterGain: GainNode | null = null;
  private masterCompressor: DynamicsCompressorNode | null = null;
  private masterMeter: AnalyserNode | null = null;
  private destination: MediaStreamAudioDestinationNode | null = null;
  private workletInitialized = false;

  constructor() {
    this.channels = new Map();
  }

  // Allow configuring latency/sample rate for "Driver" simulation
  async initialize(latencyHint: AudioContextLatencyCategory | number = 'interactive', sampleRate: number = 48000) {
    if (this.context) {
        if (this.context.state !== 'closed') await this.context.close();
    }

    // @ts-ignore - Some browsers strictly enforce typed latencyHint
    this.context = new window.AudioContext({ latencyHint, sampleRate });
    this.workletInitialized = false;

    // Load AudioWorklet (Multithreading)
    try {
        const blob = new Blob([GATE_PROCESSOR_CODE], { type: 'application/javascript' });
        const url = URL.createObjectURL(blob);
        await this.context.audioWorklet.addModule(url);
        this.workletInitialized = true;
        console.log("OmniGate Processor Loaded on Audio Thread");
    } catch (e) {
        console.warn("Failed to load AudioWorklet, Gates will be bypassed", e);
    }

    // Master Bus Chain
    this.masterCompressor = this.context.createDynamicsCompressor();
    this.masterCompressor.threshold.value = -24;
    this.masterCompressor.ratio.value = 12;

    this.masterGain = this.context.createGain();

    // Master Meter Setup
    this.masterMeter = this.context.createAnalyser();
    this.masterMeter.fftSize = 1024;
    this.masterMeter.smoothingTimeConstant = 0.8;

    this.destination = this.context.createMediaStreamDestination();

    // Chain: Comp -> Gain -> Meter -> Out
    this.masterCompressor.connect(this.masterGain);
    this.masterGain.connect(this.masterMeter);
    this.masterMeter.connect(this.context.destination); // Monitoring
    this.masterMeter.connect(this.destination); // Broadcast Stream
  }

  createChannelStrip(id: number) {
    if (!this.context) return;

    // Create Nodes
    let gateNode: AudioWorkletNode | null = null;

    if (this.workletInitialized) {
        gateNode = new AudioWorkletNode(this.context, 'omni-gate', {
            numberOfInputs: 1,
            numberOfOutputs: 1,
            outputChannelCount: [2]
        });
    }

    const compressorNode = this.context.createDynamicsCompressor();
    // Default Comp Settings (neutral)
    compressorNode.threshold.value = 0; 
    compressorNode.ratio.value = 1;

    const eqLow = this.context.createBiquadFilter();
    eqLow.type = 'lowshelf';
    eqLow.frequency.value = 320;

    const eqMid = this.context.createBiquadFilter();
    eqMid.type = 'peaking';
    eqMid.frequency.value = 1000;
    eqMid.Q.value = 1.0;

    const eqHigh = this.context.createBiquadFilter();
    eqHigh.type = 'highshelf';
    eqHigh.frequency.value = 3200;

    const panNode = this.context.createStereoPanner();
    const gainNode = this.context.createGain();
    const meterNode = this.context.createAnalyser();
    meterNode.fftSize = 1024;
    meterNode.smoothingTimeConstant = 0.8;

    // Chain: Source -> Gate -> Comp -> EQ -> Pan -> Gain -> Meter -> Master
    // Note: Source is connected later.

    // Internal Chain Construction
    let inputHead: AudioNode = eqLow;

    if (gateNode) {
        gateNode.connect(compressorNode);
        compressorNode.connect(eqLow);
        inputHead = gateNode;
    } else {
        compressorNode.connect(eqLow);
        inputHead = compressorNode;
    }

    eqLow.connect(eqMid);
    eqMid.connect(eqHigh);
    eqHigh.connect(panNode);
    panNode.connect(gainNode);
    gainNode.connect(meterNode);

    // Initial Master Connection
    if (this.masterCompressor) {
      meterNode.connect(this.masterCompressor); 
    }

    this.channels.set(id, {
      source: null,
      gateNode,
      compressorNode,
      eqLow,
      eqMid,
      eqHigh,
      panNode,
      gainNode,
      meterNode,
      stream: null
    });
  }

  async setInputDevice(id: number, deviceId: string) {
    if (!this.context) return;
    const ch = this.channels.get(id);
    if (!ch) return;

    // Cleanup old stream
    if (ch.stream) {
      ch.stream.getTracks().forEach(t => t.stop());
      if (ch.source) ch.source.disconnect();
    }

    if (!deviceId) return;

    try {
      let stream: MediaStream;
      if (deviceId === 'display-capture') {
         // @ts-ignore
         stream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true });
      } else {
         stream = await navigator.mediaDevices.getUserMedia({
            audio: { 
                deviceId: { exact: deviceId },
                echoCancellation: false,
                noiseSuppression: false,
                autoGainControl: false,
                channelCount: 2
            }
         });
      }

      const source = this.context.createMediaStreamSource(stream);
      ch.stream = stream;
      ch.source = source;

      // Connect to the head of the chain (Gate or Comp)
      const head = ch.gateNode || ch.compressorNode;
      source.connect(head);

    } catch (err) {
      console.error(`Failed to set device for Ch ${id}`, err);
    }
  }

  updateChannel(settings: ChannelSettings) {
    if (!this.context) return;
    const ch = this.channels.get(settings.id);
    if (!ch) return;

    // 1. Dynamics - Gate (AudioWorklet)
    if (ch.gateNode) {
        const bypass = settings.gate.active ? 0 : 1;
        // Params are k-rate (AudioParam)
        const thresholdParam = (ch.gateNode.parameters as any).get('threshold');
        const bypassParam = (ch.gateNode.parameters as any).get('bypass');

        if (thresholdParam) thresholdParam.setValueAtTime(settings.gate.threshold, this.context.currentTime);
        if (bypassParam) bypassParam.setValueAtTime(bypass, this.context.currentTime);
    }

    // 2. Dynamics - Compressor
    const comp = ch.compressorNode;
    if (settings.compressor.active) {
        comp.threshold.setTargetAtTime(settings.compressor.threshold, this.context.currentTime, 0.1);
        comp.ratio.setTargetAtTime(settings.compressor.ratio, this.context.currentTime, 0.1);
    } else {
        // Neutralize compressor
        comp.threshold.setTargetAtTime(0, this.context.currentTime, 0.1);
        comp.ratio.setTargetAtTime(1, this.context.currentTime, 0.1);
    }

    // 3. EQ
    ch.eqLow.gain.setTargetAtTime(settings.eq.low, this.context.currentTime, 0.1);
    ch.eqMid.gain.setTargetAtTime(settings.eq.mid, this.context.currentTime, 0.1);
    ch.eqHigh.gain.setTargetAtTime(settings.eq.high, this.context.currentTime, 0.1);

    // 4. Pan & Gain
    ch.panNode.pan.setTargetAtTime(settings.pan, this.context.currentTime, 0.1);

    // Mute/Solo Logic
    const gainVal = settings.mute ? 0 : settings.gain;
    ch.gainNode.gain.setTargetAtTime(gainVal, this.context.currentTime, 0.05);
  }

  updateMaster(settings: MasterSettings) {
    if (!this.masterGain || !this.context) return;
    this.masterGain.gain.setTargetAtTime(settings.masterGain, this.context.currentTime, 0.1);
    // Reverb/Delay/AEC logic would be here (omitted for brevity)
  }

  private calculateRMSAndPeak(analyser: AnalyserNode): AudioMeterData {
    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyser.getByteTimeDomainData(dataArray);

    let sum = 0;
    let peak = 0;
    for (let i = 0; i < bufferLength; i++) {
      const float = (dataArray[i] - 128) / 128;
      sum += float * float;
      if (Math.abs(float) > peak) peak = Math.abs(float);
    }
    const rms = Math.sqrt(sum / bufferLength);
    return { rms, peak };
  }

  getMeter(id: number): AudioMeterData {
    const ch = this.channels.get(id);
    if (!ch) return { rms: 0, peak: 0 };
    return this.calculateRMSAndPeak(ch.meterNode);
  }

  getMasterMeter(): AudioMeterData {
    if (!this.masterMeter) return { rms: 0, peak: 0 };
    return this.calculateRMSAndPeak(this.masterMeter);
  }

  calculateOptimalMasterGain(): number {
      // Analyze current channel peaks to determine safe master gain
      let totalPeak = 0;
      this.channels.forEach(ch => {
          const { peak } = this.calculateRMSAndPeak(ch.meterNode);
          totalPeak += peak;
      });

      // If total possible amplitude > 1, we attenuate.
      // Target -1.0 dB (approx 0.89 linear) headroom
      if (totalPeak > 0.89) {
          return 0.89 / totalPeak;
      }
      return 1.0; // Default to unity if clean
  }

  getContextTime() {
    return this.context?.currentTime || 0;
  }

  getContextState() {
    return this.context?.state || 'uninitialized';
  }

  async tryResumeContext() {
    if (this.context && this.context.state === 'suspended') {
        await this.context.resume();
    }
  }

  async switchChannelToDefault(id: number) {
      const ch = this.channels.get(id);
      if(ch && ch.stream) {
          ch.stream.getTracks().forEach(t => t.stop());
      }
      await this.setInputDevice(id, 'default');
  }
}

