    const [isDragging, setIsDragging] = useState(false);
    const startY = useRef(0);
    const startVal = useRef(0);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging) return;
            const deltaY = startY.current - e.clientY;
            let newVal = startVal.current + deltaY * 0.01;
            newVal = Math.max(0, Math.min(1, newVal));
            onChange(newVal);
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, onChange]);

    const rotation = (value * 270) - 135;

    return (
        <div className="flex flex-col items-center">
            <span className="text-[9px] opacity-60 mb-2 font-bold">{label}</span>
            <div 
                className="w-12 h-12 rounded-full skeuo-knob flex items-center justify-center relative cursor-ns-resize group shadow-lg"
                onMouseDown={(e) => {
                    setIsDragging(true);
                    startY.current = e.clientY;
                    startVal.current = value;
