interface Props {
  settings: ChannelSettings;
  onChange: (settings: ChannelSettings) => void;
  inputDevices: MediaDeviceInfo[];
  onOptimize: () => void;
}

const Knob = ({ value, onChange, label, min, max, color = "blue", size = "w-10 h-10" }: any) => {
    const [isDragging, setIsDragging] = useState(false);
    const startY = useRef(0);
    const startVal = useRef(0);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isDragging) return;
            const deltaY = startY.current - e.clientY;
            const range = max - min;
            let newVal = startVal.current + deltaY * (range / 200);
            newVal = Math.max(min, Math.min(max, newVal));
            onChange(newVal);
        };
        const handleMouseUp = () => setIsDragging(false);
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);
        }
        return () => {
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isDragging, onChange, min, max]);

    const percentage = (value - min) / (max - min);
    const rotation = (percentage * 270) - 135;

    const indicatorColor = color === "green" ? "bg-green-500" : color === "red" ? "bg-red-500" : "bg-blue-500";

    return (
        <div className="flex flex-col items-center gap-1">
            <div 
                className={`${size} rounded-full skeuo-knob flex items-center justify-center relative cursor-ns-resize group`}
                onMouseDown={(e) => {
                    setIsDragging(true);
                    startY.current = e.clientY;
                    startVal.current = value;
                }}
            >
              <div 
                className={`absolute w-0.5 h-1/2 ${indicatorColor} rounded-full origin-bottom top-[10%] transition-transform duration-75`} 
                style={{ transform: `rotate(${rotation}deg) translateY(-50%)` }}
              />
            </div>
            {label && <span className="text-[8px] font-bold text-gray-500 uppercase">{label}</span>}
        </div>
    );
};

const MixerStrip: React.FC<Props> = ({ settings, onChange, inputDevices, onOptimize }) => {
  const [meter, setMeter] = useState<AudioMeterData>({ rms: 0, peak: 0 });
  const [hasError, setHasError] = useState(false);
  const meterRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
        const data = audioEngine.getMeter(settings.id);
        setMeter(data);
        if (meterRef.current) {
            const height = Math.min(100, data.peak * 100);
            meterRef.current.style.height = `${height}%`;
            if (data.peak > 0.9) meterRef.current.style.backgroundColor = '#f87171';
            else if (data.peak > 0.7) meterRef.current.style.backgroundColor = '#eab308';
            else meterRef.current.style.backgroundColor = '#4ade80';
        }
    }, 50);
    return () => clearInterval(interval);
  }, [settings.id]);

  const handleDeviceSelect = async (deviceId: string) => {
    setHasError(false);
    try {
        await audioEngine.setInputDevice(settings.id, deviceId);
        onChange({ ...settings, deviceId });
    } catch (e: any) {
        setHasError(true);
        alert(e.message || "Failed to initialize audio device.");
    }
  };

  return (
    <div className="w-32 bg-[#1a1a1a] border-r border-[#333] flex flex-col items-center py-2 shrink-0 skeuo-shadow relative">

      {/* Header & Optimize */}
      <div className="w-full px-2 mb-2 flex flex-col gap-1">
        <div className="flex justify-between items-center bg-[#111] p-1 rounded border border-[#333]">
            <div className="flex items-center gap-1">
                <span className="text-[10px] font-bold text-gray-400">CH.{settings.id}</span>
                {hasError && <AlertCircle size={10} className="text-red-500 animate-pulse" />}
            </div>
            <button onClick={onOptimize} className="text-yellow-500 hover:text-white" title="AI Optimize">
                {ICONS.Zap}
            </button>
        </div>

        {/* Input Selector */}
        <div className="relative group w-full">
            <button className={`flex items-center justify-between w-full text-[9px] bg-[#0a0a0a] p-1.5 rounded border ${hasError ? 'border-red-900 shadow-[inset_0_0_5px_rgba(255,0,0,0.2)]' : 'border-[#333]'} hover:border-blue-500 truncate text-gray-300`}>
                <span className="truncate w-16 text-left">
                    {inputDevices.find(d => d.deviceId === settings.deviceId)?.label || "Select Input"}
                </span>
                <ChevronDown size={8} />
            </button>
            <div className="absolute top-full left-0 w-48 bg-[#151515] border border-[#444] z-50 hidden group-hover:block max-h-48 overflow-y-auto shadow-2xl rounded-b">
                {inputDevices.map(device => (
                    <div 
                        key={device.deviceId} 
                        onClick={() => handleDeviceSelect(device.deviceId)}
                        className={`p-2 text-[10px] hover:bg-blue-900 cursor-pointer truncate ${device.deviceId === settings.deviceId ? 'text-blue-400 font-bold bg-white/5' : 'text-gray-300'}`}
                        title={device.label}
                    >
                        {device.label || `Device ${device.deviceId.substring(0,8)}...`}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Dynamics Section */}
      <div className="w-[90%] bg-[#111] rounded border border-[#333] p-1 mb-2 flex flex-col gap-1">
         <span className="text-[8px] text-center text-gray-500 font-bold border-b border-[#333] pb-0.5">DYNAMICS</span>
         <div className="flex justify-between px-1">
            <div className="flex flex-col items-center">
                 <button 
                    onClick={() => onChange({...settings, gate: {...settings.gate, active: !settings.gate.active}})}
                    className={`text-[8px] mb-1 px-1 rounded ${settings.gate.active ? 'bg-green-900 text-green-400' : 'bg-[#222] text-gray-600'}`}
                 >GATE</button>
                 <Knob 
                    value={settings.gate.threshold} 
                    min={-80} max={0} 
                    onChange={(v: number) => onChange({...settings, gate: {...settings.gate, threshold: v}})}
                    size="w-6 h-6"
                    color="green"
                 />
            </div>
            <div className="flex flex-col items-center">
                 <button 
                    onClick={() => onChange({...settings, compressor: {...settings.compressor, active: !settings.compressor.active}})}
                    className={`text-[8px] mb-1 px-1 rounded ${settings.compressor.active ? 'bg-yellow-900 text-yellow-400' : 'bg-[#222] text-gray-600'}`}
                 >COMP</button>
                 <Knob 
                    value={settings.compressor.ratio} 
                    min={1} max={20} 
                    onChange={(v: number) => onChange({...settings, compressor: {...settings.compressor, ratio: v}})}
                    size="w-6 h-6"
                    color="yellow"
                 />
            </div>
         </div>
      </div>

      {/* EQ Section */}
      <div className="flex flex-col gap-2 bg-[#222] p-2 rounded-lg border border-[#333] mb-2 skeuo-shadow">
        <Knob label="HIGH" value={settings.eq.high} min={-12} max={12} onChange={(v:number) => onChange({ ...settings, eq: { ...settings.eq, high: v }})} />
        <Knob label="MID" value={settings.eq.mid} min={-12} max={12} onChange={(v:number) => onChange({ ...settings, eq: { ...settings.eq, mid: v }})} />
        <Knob label="LOW" value={settings.eq.low} min={-12} max={12} onChange={(v:number) => onChange({ ...settings, eq: { ...settings.eq, low: v }})} />
      </div>

      {/* Pan */}
      <div className="mb-2">
         <Knob label="PAN" value={settings.pan} min={-1} max={1} onChange={(v:number) => onChange({ ...settings, pan: v })} color="red" size="w-8 h-8" />
      </div>

      {/* Mute/Solo/Monitor */}
      <div className="flex flex-col gap-1 w-full px-2 mb-2">
         <div className="flex gap-1">
            <button 
                onClick={() => onChange({ ...settings, mute: !settings.mute })}
                className={`flex-1 py-1 text-[9px] font-bold border rounded shadow-sm ${settings.mute ? 'bg-red-600 border-red-400 text-white led-red' : 'bg-[#333] border-[#444] text-gray-400'}`}
            >M</button>
            <button 
                onClick={() => onChange({ ...settings, solo: !settings.solo })}
                className={`flex-1 py-1 text-[9px] font-bold border rounded shadow-sm ${settings.solo ? 'bg-yellow-500 border-yellow-300 text-black led-yellow' : 'bg-[#333] border-[#444] text-gray-400'}`}
            >S</button>
         </div>
         <button 
            onClick={() => onChange({ ...settings, monitor: !settings.monitor })}
            className={`w-full py-1 text-[9px] font-bold border rounded flex justify-center gap-1 ${settings.monitor ? 'bg-blue-600 border-blue-400 text-white led-blue' : 'bg-[#222] border-[#333] text-gray-500'}`}
         >
             <Power size={10} /> MONITOR
         </button>
      </div>

      {/* Fader & Meter */}
      <div className="flex-grow flex justify-center gap-2 h-48 w-full px-2 relative">
        <div className="w-2 bg-[#111] h-full rounded-full border border-[#333] overflow-hidden relative flex flex-col-reverse">
            <div ref={meterRef} className="w-full bg-green-500 transition-all duration-75 ease-out opacity-80" style={{height: '0%'}} />
            <div className="absolute inset-0 flex flex-col justify-between py-1 pointer-events-none">
                {[...Array(10)].map((_, i) => <div key={i} className="w-full h-px bg-white/20" />)}
            </div>
        </div>

        <div className="w-8 bg-[#000] h-full rounded border border-[#333] relative">
            <div className="absolute top-[10%] bottom-[10%] left-1/2 -translate-x-1/2 w-0.5 bg-[#222]" />
            <input 
                type="range"
                min="0" max="1.2" step="0.01"
                value={settings.gain}
                onChange={(e) => onChange({ ...settings, gain: parseFloat(e.target.value) })}
                className="absolute -rotate-90 w-40 h-8 -left-16 top-20 opacity-0 cursor-pointer z-20"
            />
            <div 
                className="absolute left-0 w-full h-8 bg-gradient-to-b from-[#555] to-[#222] border-y border-[#666] shadow-xl z-10 pointer-events-none flex items-center justify-center"
                style={{ bottom: `${(settings.gain / 1.2) * 80}%`, transition: 'bottom 0.1s' }}
            >
                <div className="w-full h-px bg-black/50" />
            </div>
        </div>
      </div>

      <div className="mt-2 bg-[#111] px-2 py-1 rounded text-[10px] font-mono text-green-400 border border-[#333]">
        {settings.gain === 0 ? '-inf' : `${(20 * Math.log10(settings.gain)).toFixed(1)}`} dB
      </div>

    </div>
  );
};

export default MixerStrip;
